import { arrayIncludes, getDistinct } from '../../../../utils/zcutils';
import { d3_map } from '../../../../core/d3-constants';

/**
 *
 * @param legendPoint
 * @param chartInstance
 * @param states
 * @return {[]}
 */
export function getSankeyDependentPoint(legendPoint, chartInstance, states) {
    let sankeyLayout = chartInstance.dataObject.sankeyLayout,
        legendItemsMap = d3_map(chartInstance.cache.sankey.legendSankeyLayout.nodes, n => n.name),
        enableManually = (!states.allSelected && !states.isFirstClickAfterDeselection) || legendPoint.disabled,
        node = legendPoint.node || chartInstance.renderer[0].getSankeyNodeByPoint(legendPoint, legendItemsMap),
        enableList = [];

    if (enableManually) {
        [...node.sourceLinks, ...node.targetLinks].forEach(link => {
            enableList = [...enableList, ...sankeyLayout.getConnectedNodes(link)];
        });
        enableList = getDistinct(enableList.map(node => node.point));
    }
    return enableList;
}

/**
 *
 * @param legendPoint
 * @param chartInstance
 * @return {[]}
 */
export function getEmptySankeyNode(legendPoint, chartInstance) {
    let layout = chartInstance.dataObject.sankeyLayout;
    let currentNode = chartInstance.renderer[0].getSankeyNodeByPoint(legendPoint),
        emptyNodes = [];

    if (currentNode) {
        const accessor = {visibility: (link, name) => name === 'source' ? link : null }
        let allConnectedPoints = layout.getAllConnectedPoints(currentNode, true, accessor),
            allConnectedLinks = allConnectedPoints.filter(p => p._type === 'link'),
            allConnectedNodes = allConnectedPoints.filter(p => p._type === 'node');

        allConnectedNodes.forEach(node => {
            if (node !== currentNode) {
                let links = [...node.sourceLinks, ...node.targetLinks].filter(link => {
                    return !arrayIncludes(allConnectedLinks, link);
                });

                if (links.length === 0) {
                    emptyNodes.push(node.point);
                }
            }
        });
    }

    return emptyNodes;
}
